package com.veetu.vadagai.property;import com.veetu.vadagai.common.BaseEntity;import com.veetu.vadagai.user.User;import jakarta.persistence.*;import jakarta.validation.constraints.*;import lombok.*;import java.math.BigDecimal;
@Entity @Table(name="properties",indexes={@Index(name="idx_property_owner",columnList="owner_id"),@Index(name="idx_property_city",columnList="city")}) @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder
public class Property extends BaseEntity{ @ManyToOne(optional=false) @JoinColumn(name="owner_id") private User owner; @NotBlank @Column(nullable=false) private String title; @Enumerated(EnumType.STRING) @Column(nullable=false) private PropertyType type; @Column(nullable=false) private String addressLine1; private String addressLine2; @Column(nullable=false) private String city; @Column(nullable=false) private String state; @Column(nullable=false) private String postalCode; @Column(nullable=false,precision=12,scale=2) private BigDecimal rentAmount; @Column(nullable=false,precision=12,scale=2) private BigDecimal advanceAmount; @Column(nullable=false) private int dueDay; @Column(nullable=false) private boolean occupied; }
